  1	import * as React from 'react';
  2	import {
  3	  getName,
  4	  StorageConsumerModel,
  5	  getProvisioner,
  6	  getUID,
  7	  ModalFooter,
  8	  StorageClassModel,
  9	  StorageClassResourceKind,
 10	  StorageConsumerKind,
 11	  useCustomTranslation,
 12	  VolumeSnapshotClassKind,
 13	  VolumeSnapshotClassModel,
 14	} from '@odf/shared';
 15	import { CommonModalProps } from '@odf/shared/modals';
 16	import { isCephDriver, isCephProvisioner } from '@odf/shared/utils';
 17	import {
 18	  WatchK8sResources,
 19	  useK8sWatchResources,
 20	  k8sPatch,
 21	} from '@openshift-console/dynamic-plugin-sdk';
 22	import * as _ from 'lodash-es';
 23	import {
 24	  Modal,
 25	  Flex,
 26	  FlexItem,
 27	  Button,
 28	  Tabs,
 29	  Tab,
 30	  TabTitleText,
 31	  Label,
 32	} from '@patternfly/react-core';
 33	import { Tr, Td } from '@patternfly/react-table';
 34	import {
 35	  ResourceDistributionTable,
 36	  RowGeneratorProps,
 37	  SelectedResources,
 38	} from '../../components/ResourceDistribution/ResourceDistributionTable';
 39	import { generatePatchForDistributionOfResources } from '../../components/ResourceDistribution/utils';
 40	
 41	type Resources = {
 42	  storageClasses: StorageClassResourceKind[];
 43	  volumeSnapshotClasses: VolumeSnapshotClassKind[];
 44	};
 45	
 46	const resources: WatchK8sResources<Resources> = {
 47	  storageClasses: {
 48	    groupVersionKind: {
 49	      group: StorageClassModel.apiGroup,
 50	      version: StorageClassModel.apiVersion,
 51	      kind: StorageClassModel.kind,
 52	    },
 53	    isList: true,
 54	  },
 55	  volumeSnapshotClasses: {
 56	    groupVersionKind: {
 57	      group: VolumeSnapshotClassModel.apiGroup,
 58	      version: VolumeSnapshotClassModel.apiVersion,
 59	      kind: VolumeSnapshotClassModel.kind,
 60	    },
 61	    isList: true,
 62	  },
 63	};
 64	
 65	export const StorageClassRowGenerator: React.FC<
 66	  RowGeneratorProps<StorageClassResourceKind>
 67	> = ({ resource: storageClass, onSelect, isSelected, rowIndex }) => {
 68	  return (
 69	    <Tr key={getUID(storageClass)}>
 70	      <Td
 71	        select={{
 72	          rowIndex,
 73	          onSelect: (_event, isSelecting) => onSelect(isSelecting),
 74	          isSelected,
 75	        }}
 76	      />
 77	      <Td>{getName(storageClass)}</Td>
 78	      <Td>{getProvisioner(storageClass)}</Td>
 79	      <Td>{storageClass?.reclaimPolicy}</Td>
 80	    </Tr>
 81	  );
 82	};
 83	
 84	const VolumeSnapshotClassRowGenerator: React.FC<RowGeneratorProps<any>> = ({
 85	  resource: vsc,
 86	  onSelect,
 87	  isSelected,
 88	  rowIndex,
 89	}) => {
 90	  return (
 91	    <Tr key={getUID(vsc)}>
 92	      <Td
 93	        select={{
 94	          rowIndex,
 95	          onSelect: (_event, isSelecting) => onSelect(isSelecting),
 96	          isSelected,
 97	        }}
 98	      />
 99	      <Td>{getName(vsc)}</Td>
100	      <Td>{vsc?.driver}</Td>
101	      <Td>{vsc?.deletionPolicy}</Td>
102	    </Tr>
103	  );
104	};
105	
106	export const DistributeResourceModal: React.FC<
107	  CommonModalProps<{ resource: StorageConsumerKind }>
108	> = ({ closeModal, isOpen, extraProps: { resource } }) => {
109	  const { t } = useCustomTranslation();
110	  const [selectedResources, setSelectedResources] =
111	    React.useState<SelectedResources>({
112	      storageClass: {},
113	      volumeSnapshotClass: {},
114	    });
115	  const [inProgress, setProgress] = React.useState(false);
116	  const [error, setError] = React.useState('');
117	  const [activeTabKey, setActiveTabKey] = React.useState<string | number>(0);
118	
119	  const data = useK8sWatchResources<Resources>(resources);
120	  const filteredStorageClasses = data.storageClasses.data.filter((res) =>
121	    isCephProvisioner(getProvisioner(res))
122	  );
123	  const filteredVolumeSnapshotClasses = data.volumeSnapshotClasses.data.filter(
124	    (res) => isCephProvisioner(res?.driver)
125	  );
126	
127	  const isStorageClassDataLoaded = data?.storageClasses?.loaded;
128	  const isVolumeSnapshotClassDataLoaded = data?.volumeSnapshotClasses?.loaded;
129	
130	  const handleTabClick = (_event, tabIndex: string | number) => {
131	    setActiveTabKey(tabIndex);
132	  };
133	
134	  const selectedStorageClassesCount = Object.entries(
135	    selectedResources?.storageClass
136	  ).filter(([, value]) => !!value).length;
137	  const selectedVolumeSnapshotClassesCount = Object.entries(
138	    selectedResources?.volumeSnapshotClass
139	  ).filter(([, value]) => !!value).length;
140	
141	  React.useEffect(() => {
142	    if (
143	      isStorageClassDataLoaded &&
144	      isVolumeSnapshotClassDataLoaded &&
145	      _.isEmpty(selectedResources.storageClass) &&
146	      _.isEmpty(selectedResources.volumeSnapshotClass)
147	    ) {
148	      const preselectedStorageClasses = resource.spec?.storageClasses?.map(
149	        (sc) => sc?.name
150	      );
151	      const preselectedVolumeSnapshotClasses =
152	        resource.spec?.volumeSnapshotClasses?.map((vsc) => vsc?.name);
153	      const newSelectedResources: SelectedResources = {
154	        storageClass: {},
155	        volumeSnapshotClass: {},
156	      };
157	      newSelectedResources.storageClass = data.storageClasses.data
158	        .filter((sc) => isCephProvisioner(getProvisioner(sc)))
159	        .reduce((acc, storageClass) => {
160	          acc[getName(storageClass)] = preselectedStorageClasses?.includes(
161	            getName(storageClass)
162	          );
163	          return acc;
164	        }, {});
165	      newSelectedResources.volumeSnapshotClass = data.volumeSnapshotClasses.data
166	        .filter((vsc) => isCephDriver(vsc?.driver))
167	        .reduce((acc, vs) => {
168	          acc[getName(vs)] = preselectedVolumeSnapshotClasses?.includes(
169	            getName(vs)
170	          );
171	          return acc;
172	        }, {});
173	      setSelectedResources(newSelectedResources);
174	    }
175	  }, [
176	    data.storageClasses.data,
177	    data.storageClasses.loaded,
178	    data.volumeSnapshotClasses.data,
179	    isStorageClassDataLoaded,
180	    isVolumeSnapshotClassDataLoaded,
181	    resource.spec?.storageClasses,
182	    resource.spec?.volumeGroupSnapshotClasses,
183	    resource.spec?.volumeSnapshotClasses,
184	    selectedResources,
185	  ]);
186	
187	  const onConfirm = () => {
188	    const selectedStorageClasses = Object.entries(
189	      selectedResources.storageClass
190	    )
191	      .filter(([, value]) => value)
192	      .map(([key]) => key);
193	    const selectedVolumeSnapshotClasses = Object.entries(
194	      selectedResources.volumeSnapshotClass
195	    )
196	      .filter(([, value]) => value)
197	      .map(([key]) => key);
198	    const patch = generatePatchForDistributionOfResources(
199	      resource,
200	      selectedStorageClasses,
201	      selectedVolumeSnapshotClasses
202	    );
203	    setProgress(true);
204	    k8sPatch({ model: StorageConsumerModel, resource, data: patch })
205	      .then(() => {
206	        setProgress(false);
207	        closeModal();
208	      })
209	      .catch((err) => {
210	        setProgress(false);
211	        setError(err.message);
212	      });
213	  };
214	  return (
215	    <Modal
216	      title={t('Manage distribution of resources')}
217	      isOpen
218	      onClose={closeModal}
219	      open={isOpen}
220	      variant="medium"
221	    >
222	      <Tabs activeKey={activeTabKey} onSelect={handleTabClick}>
223	        <Tab
224	          eventKey={0}
225	          title={
226	            <TabTitleText>
227	              {t('Storage classes')}{' '}
228	              <Label>{selectedStorageClassesCount}</Label>
229	            </TabTitleText>
230	          }
231	        >
232	          <ResourceDistributionTable
233	            resources={filteredStorageClasses}
234	            selectedResources={selectedResources}
235	            setSelectedResources={setSelectedResources}
236	            RowGenerator={StorageClassRowGenerator}
237	            loaded={isStorageClassDataLoaded}
238	            columns={[t('Name'), t('Provisioner'), t('Deletion policy')]}
239	            resourceType="storageClass"
240	          />
241	        </Tab>
242	        <Tab
243	          eventKey={1}
244	          title={
245	            <TabTitleText>
246	              {t('VolumeSnapshot classes')}{' '}
247	              <Label>{selectedVolumeSnapshotClassesCount}</Label>
248	            </TabTitleText>
249	          }
250	        >
251	          <ResourceDistributionTable
252	            resources={filteredVolumeSnapshotClasses}
253	            selectedResources={selectedResources}
254	            setSelectedResources={setSelectedResources}
255	            RowGenerator={VolumeSnapshotClassRowGenerator}
256	            loaded={isVolumeSnapshotClassDataLoaded}
257	            columns={[t('Name'), t('Driver'), t('Deletion policy')]}
258	            resourceType="volumeSnapshotClass"
259	          />
260	        </Tab>
261	      </Tabs>
262	      <ModalFooter inProgress={inProgress} errorMessage={error}>
263	        <Flex direction={{ default: 'row' }}>
264	          <FlexItem>
265	            <Button key="Cancel" variant="secondary" onClick={closeModal}>
266	              {t('Cancel')}
267	            </Button>
268	          </FlexItem>
269	          <FlexItem>
270	            <Button key="Confirm" variant="primary" onClick={onConfirm}>
271	              {t('Save changes')}
272	            </Button>
273	          </FlexItem>
274	        </Flex>
275	      </ModalFooter>
276	    </Modal>
277	  );
278	};
279	
280	export default DistributeResourceModal;

