 52	      version: StorageClassModel.apiVersion,
 53	      kind: StorageClassModel.kind,
 54	    },
 55	    isList: true,
 56	  },
 57	  volumeSnapshotClasses: {
 58	    groupVersionKind: {
 59	      group: VolumeSnapshotClassModel.apiGroup,
 60	      version: VolumeSnapshotClassModel.apiVersion,
 61	      kind: VolumeSnapshotClassModel.kind,
 62	    },
 63	    isList: true,
 64	  },
 65	};
