 67	export const StorageClassRowGenerator: React.FC<
 68	  RowGeneratorProps<StorageClassResourceKind>
 69	> = ({ resource: storageClass, onSelect, isSelected, rowIndex }) => {
 70	  return (
 71	    <Tr key={getUID(storageClass)}>
 72	      <Td
 73	        select={{
 74	          rowIndex,
 75	          onSelect: (_event, isSelecting) => onSelect(isSelecting),
 76	          isSelected,
 77	        }}
 78	      />
 79	      <Td>{getName(storageClass)}</Td>
 80	      <Td>{getProvisioner(storageClass)}</Td>
 81	      <Td>{storageClass?.reclaimPolicy}</Td>
 82	    </Tr>
