108	export const DistributeResourceModal: React.FC<
109	  CommonModalProps<{ resource: StorageConsumerKind }>
110	> = ({ closeModal, isOpen, extraProps: { resource } }) => {
111	  const { t } = useCustomTranslation();
112	  const [selectedResources, setSelectedResources] =
113	    React.useState<SelectedResources>({
114	      storageClass: {},
115	      volumeSnapshotClass: {},
116	    });
117	  const [inProgress, setProgress] = React.useState(false);
118	  const [error, setError] = React.useState('');
119	  const [activeTabKey, setActiveTabKey] = React.useState<string | number>(0);
120	
121	  const data = useK8sWatchResources<Resources>(resources);
122	  const filteredStorageClasses = data.storageClasses.data.filter((res) =>
123	    isCephProvisioner(getProvisioner(res))
124	  );
125	  const filteredVolumeSnapshotClasses = data.volumeSnapshotClasses.data.filter(
126	    (res) => isCephProvisioner(res?.driver)
127	  );
128	
129	  const isStorageClassDataLoaded = data?.storageClasses?.loaded;
130	  const isVolumeSnapshotClassDataLoaded = data?.volumeSnapshotClasses?.loaded;
131	
132	  const handleTabClick = (_event, tabIndex: string | number) => {
133	    setActiveTabKey(tabIndex);
134	  };
135	
136	  const selectedStorageClassesCount = Object.entries(
137	    selectedResources?.storageClass
138	  ).filter(([, value]) => !!value).length;
139	  const selectedVolumeSnapshotClassesCount = Object.entries(
140	    selectedResources?.volumeSnapshotClass
141	  ).filter(([, value]) => !!value).length;
142	
143	  React.useEffect(() => {
144	    if (
145	      isStorageClassDataLoaded &&
146	      isVolumeSnapshotClassDataLoaded &&
147	      _.isEmpty(selectedResources.storageClass) &&
148	      _.isEmpty(selectedResources.volumeSnapshotClass)
149	    ) {
150	      const preselectedStorageClasses = resource.spec?.storageClasses?.map(
151	        (sc) => sc?.name
152	      );
153	      const preselectedVolumeSnapshotClasses =
154	        resource.spec?.volumeSnapshotClasses?.map((vsc) => vsc?.name);
155	      const newSelectedResources: SelectedResources = {
156	        storageClass: {},
157	        volumeSnapshotClass: {},
158	      };
159	      newSelectedResources.storageClass = data.storageClasses.data
160	        .filter((sc) => isCephProvisioner(getProvisioner(sc)))
161	        .reduce((acc, storageClass) => {
162	          acc[getName(storageClass)] = preselectedStorageClasses?.includes(
163	            getName(storageClass)
164	          );
165	          return acc;
166	        }, {});
167	      newSelectedResources.volumeSnapshotClass = data.volumeSnapshotClasses.data
168	        .filter((vsc) => isCephDriver(vsc?.driver))
169	        .reduce((acc, vs) => {
170	          acc[getName(vs)] = preselectedVolumeSnapshotClasses?.includes(
171	            getName(vs)
172	          );
173	          return acc;
174	        }, {});
175	      setSelectedResources(newSelectedResources);
176	    }
177	  }, [
178	    data.storageClasses.data,
179	    data.storageClasses.loaded,
180	    data.volumeSnapshotClasses.data,
181	    isStorageClassDataLoaded,
182	    isVolumeSnapshotClassDataLoaded,
183	    resource.spec?.storageClasses,
184	    resource.spec?.volumeGroupSnapshotClasses,
185	    resource.spec?.volumeSnapshotClasses,
186	    selectedResources,
187	  ]);
188	
189	  const onConfirm = () => {
190	    const selectedStorageClasses = Object.entries(
191	      selectedResources.storageClass
192	    )
193	      .filter(([, value]) => value)
194	      .map(([key]) => key);
195	    const selectedVolumeSnapshotClasses = Object.entries(
196	      selectedResources.volumeSnapshotClass
197	    )
198	      .filter(([, value]) => value)
199	      .map(([key]) => key);
200	    const patch = generatePatchForDistributionOfResources(
201	      resource,
202	      selectedStorageClasses,
203	      selectedVolumeSnapshotClasses
204	    );
205	    setProgress(true);
206	    k8sPatch({ model: StorageConsumerModel, resource, data: patch })
207	      .then(() => {
208	        setProgress(false);
209	        closeModal();
210	      })
211	      .catch((err) => {
212	        setProgress(false);
213	        setError(err.message);
214	      });
215	  };
216	  return (
217	    <Modal
218	      isOpen
219	      onClose={closeModal}
220	      open={isOpen}
221	      variant="medium"
222	    >
223	      <ModalHeader title={t('Manage distribution of resources')} />
224	      <ModalBody>
225	      <Tabs activeKey={activeTabKey} onSelect={handleTabClick}>
226	        <Tab
227	          eventKey={0}
228	          title={
229	            <TabTitleText>
230	              {t('Storage classes')}{' '}
231	              <Label>{selectedStorageClassesCount}</Label>
232	            </TabTitleText>
233	          }
234	        >
235	          <ResourceDistributionTable
236	            resources={filteredStorageClasses}
237	            selectedResources={selectedResources}
238	            setSelectedResources={setSelectedResources}
239	            RowGenerator={StorageClassRowGenerator}
240	            loaded={isStorageClassDataLoaded}
241	            columns={[t('Name'), t('Provisioner'), t('Deletion policy')]}
242	            resourceType="storageClass"
243	          />
244	        </Tab>
245	        <Tab
246	          eventKey={1}
247	          title={
248	            <TabTitleText>
249	              {t('VolumeSnapshot classes')}{' '}
250	              <Label>{selectedVolumeSnapshotClassesCount}</Label>
251	            </TabTitleText>
252	          }
253	        >
254	          <ResourceDistributionTable
255	            resources={filteredVolumeSnapshotClasses}
256	            selectedResources={selectedResources}
257	            setSelectedResources={setSelectedResources}
258	            RowGenerator={VolumeSnapshotClassRowGenerator}
259	            loaded={isVolumeSnapshotClassDataLoaded}
260	            columns={[t('Name'), t('Driver'), t('Deletion policy')]}
261	            resourceType="volumeSnapshotClass"
262	          />
263	        </Tab>
264	      </Tabs>
265	      </ModalBody>
266	      <ModalFooter inProgress={inProgress} errorMessage={error}>
267	        <Flex direction={{ default: 'row' }}>
268	          <FlexItem>
269	            <Button key="Cancel" variant="secondary" onClick={closeModal}>
270	              {t('Cancel')}
271	            </Button>
272	          </FlexItem>
273	          <FlexItem>
274	            <Button key="Confirm" variant="primary" onClick={onConfirm}>
275	              {t('Save changes')}
276	            </Button>
277	          </FlexItem>
278	        </Flex>
279	      </ModalFooter>
280	    </Modal>
281	  );
282	};
283	
284	export default DistributeResourceModal;

