112	        <Thead>
113	          <Tr>
114	            <Th
115	              select={{
116	                onSelect: (_event, isSelecting) =>
117	                  selectAllResources(isSelecting),
118	                isSelected: areAllResourcesSelected,
119	              }}
120	            />
